# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <stdlib.h>

// Struct to hold the information about an opened file
typedef struct {
    int handle; // File Handle
} FileDescriptorInfo;

// Node for our linked list
typedef struct Node {
    FileDescriptorInfo fdInfo; 
    struct Node *next; 
} Node;

static Node* head = NULL;

void add(int fileHandle) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    
    if(!newNode){
        printf("Memory error\n");
        return;
    }

    newNode->fdInfo.handle = fileHandle;
    newNode->next = head;
    head = newNode; 
}

void remove(int fileHandle) {
    Node *temp = head, *prev;
    
    // If list is empty
    if (temp == NULL) return;  
    
    // Store head node
    if (temp != NULL && temp->fdInfo.handle == fileHandle) { 
        head = temp->next;  
        free(temp);           
        return;     
    } 

    while (temp != NULL && temp->fdInfo.handle != fileHandle) {  
        prev = temp;  
        temp = temp->next;  
    } 

    if(temp == NULL) return; // Item not found in the list

    prev->next = temp->next;  
    
    free(temp); 
}

void cleanup() {
    Node* currentNode = head;
    Node* nextNode;

    while (currentNode != NULL) {
        close(currentNode->fdInfo.handle); // assuming we have a function to handle closing of file handles
        nextNode = currentNode->next;  
        free(currentNode); 
        currentNode = nextNode;
    }
    
    head = NULL; // Clearing the head as list is now empty
}